import React from "react";
import { AppBar, Toolbar,Typography, Button } from "@mui/material";
import colouriskologo from "../../items/Frame.png";
import { Avatar } from "@mui/material";
const Navbar = () => {
  return (
    <div className="navbar">
      <AppBar sx={{ background: "#FFFFFF" }} elevation={0}>
        <Toolbar style={{ justifyContent: "space-between", display: "flex" }}>
          <Avatar
            variant={"rounded"}
            alt="The image"
            src={colouriskologo}
            style={{
              width: 150,
              // height: 200,
              background: "FFFFFF",
            }}
          />
          <Typography
              variant="h2"
              color={"black"}
              fontWeight={300}
              gutterBottom
              sx={{ textAlign: { md: "center", sx: "center" } }}
            >
              HOME
            </Typography>
          <Button sx={{ color: "black", fontWeight: "800" }}>Contact</Button>
        </Toolbar>
      </AppBar>
      <Toolbar />
    </div>
  );
};

export default Navbar;
